import{_ as e,c as a,o as t,d as n}from"./app.5b93cda2.js";const f='{"title":"\u041F\u0435\u0448\u0430\u044F \u043B\u0438\u0433\u0430","description":"","frontmatter":{"title":"\u041F\u0435\u0448\u0430\u044F \u043B\u0438\u0433\u0430","subtitle":"\u0421\u0435\u0442\u0435\u0432\u043E\u0439 \u043A\u043B\u0443\u0431 \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439 \u043F\u0435\u0448\u0438\u0445 \u043F\u0440\u043E\u0433\u0443\u043B\u043E\u043A \u0441 \u0440\u0430\u0437\u043C\u0435\u0442\u043A\u043E\u0439 \u043C\u0430\u0440\u0448\u0442\u0443\u0442\u043E\u0432 \u043D\u0430 \u043A\u0430\u0440\u0442\u0435 \u0438 \u043D\u0430 \u043C\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u0438","date":"2014-12-14T00:00:00.000Z","status":"development","cover":"Silly_walk-lines.png","icon":"pl.png","type":"design"},"headers":[{"level":3,"title":"\u0427\u0435\u043B\u043E\u0432\u0435\u043A\u0443 \u043D\u0443\u0436\u043D\u043E \u0433\u0443\u043B\u044F\u0442\u044C.","slug":"\u0447\u0435n\u043E\u0432\u0435\u043A\u0443-\u043D\u0443\u0436\u043D\u043E-\u0433\u0443n\u044F\u0442\u044C"},{"level":3,"title":"\u0416\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C.","slug":"\u0436\u0435n\u0430\u0442\u0435n\u044C\u043D\u043E-\u043A\u0430\u0436\u0434\u044B\u0439-\u0434\u0435\u043D\u044C"},{"level":3,"title":"\u0425\u043E\u0440\u043E\u0448\u043E \u0431\u044B \u0432 \u043A\u0440\u0430\u0441\u0438\u0432\u044B\u0445 \u0447\u0438\u0441\u0442\u044B\u0445 \u043F\u0440\u0438\u0440\u043E\u0434\u043D\u044B\u0445 \u043C\u0435\u0441\u0442\u0430\u0445.","slug":"\u0445\u043E\u0440\u043E\u0448\u043E-\u0431\u044B-\u0432-\u043A\u0440\u0430\u0441\u0438\u0432\u044B\u0445-\u0447\u0438\u0441\u0442\u044B\u0445-\u043F\u0440\u0438\u0440\u043E\u0434\u043D\u044B\u0445-\u043C\u0435\u0441\u0442\u0430\u0445"},{"level":3,"title":"\u0418 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u043E\u043C.","slug":"\u0438-\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C-\u043C\u0430\u0440\u0448\u0440\u0443\u0442\u043E\u043C"}],"relativePath":"designs/walkers-league/index.md"}',i={},r=n('<h3 id="\u0447\u0435n\u043E\u0432\u0435\u043A\u0443-\u043D\u0443\u0436\u043D\u043E-\u0433\u0443n\u044F\u0442\u044C" tabindex="-1">\u0427\u0435\u043B\u043E\u0432\u0435\u043A\u0443 \u043D\u0443\u0436\u043D\u043E \u0433\u0443\u043B\u044F\u0442\u044C. <a class="header-anchor" href="#\u0447\u0435n\u043E\u0432\u0435\u043A\u0443-\u043D\u0443\u0436\u043D\u043E-\u0433\u0443n\u044F\u0442\u044C" aria-hidden="true">#</a></h3><h3 id="\u0436\u0435n\u0430\u0442\u0435n\u044C\u043D\u043E-\u043A\u0430\u0436\u0434\u044B\u0439-\u0434\u0435\u043D\u044C" tabindex="-1">\u0416\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C. <a class="header-anchor" href="#\u0436\u0435n\u0430\u0442\u0435n\u044C\u043D\u043E-\u043A\u0430\u0436\u0434\u044B\u0439-\u0434\u0435\u043D\u044C" aria-hidden="true">#</a></h3><h3 id="\u0445\u043E\u0440\u043E\u0448\u043E-\u0431\u044B-\u0432-\u043A\u0440\u0430\u0441\u0438\u0432\u044B\u0445-\u0447\u0438\u0441\u0442\u044B\u0445-\u043F\u0440\u0438\u0440\u043E\u0434\u043D\u044B\u0445-\u043C\u0435\u0441\u0442\u0430\u0445" tabindex="-1">\u0425\u043E\u0440\u043E\u0448\u043E \u0431\u044B \u0432 \u043A\u0440\u0430\u0441\u0438\u0432\u044B\u0445 \u0447\u0438\u0441\u0442\u044B\u0445 \u043F\u0440\u0438\u0440\u043E\u0434\u043D\u044B\u0445 \u043C\u0435\u0441\u0442\u0430\u0445. <a class="header-anchor" href="#\u0445\u043E\u0440\u043E\u0448\u043E-\u0431\u044B-\u0432-\u043A\u0440\u0430\u0441\u0438\u0432\u044B\u0445-\u0447\u0438\u0441\u0442\u044B\u0445-\u043F\u0440\u0438\u0440\u043E\u0434\u043D\u044B\u0445-\u043C\u0435\u0441\u0442\u0430\u0445" aria-hidden="true">#</a></h3><h3 id="\u0438-\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C-\u043C\u0430\u0440\u0448\u0440\u0443\u0442\u043E\u043C" tabindex="-1">\u0418 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u043E\u043C. <a class="header-anchor" href="#\u0438-\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C-\u043C\u0430\u0440\u0448\u0440\u0443\u0442\u043E\u043C" aria-hidden="true">#</a></h3><p>\u041B\u044E\u0431\u043E\u0432\u044C \u043A \u043F\u0440\u043E\u0433\u0443\u043B\u043A\u0430\u043C \u2013 \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u043A\u043B\u0443\u0431\u044B \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439 \u0433\u0443\u043B\u044F\u0442\u044C. \u041C\u044B \u0441\u043E\u0437\u0434\u0430\u0435\u043C \u043B\u043E\u043A\u0430\u043B\u044C\u043D\u044B\u0435 \u0438 \u0441\u0435\u0442\u0435\u0432\u044B\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u0442\u0435\u0445, \u043A\u0442\u043E \u0437\u043D\u0430\u0435\u0442 \u043A\u043B\u0430\u0441\u0441\u043D\u044B\u0435 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u044B \u0438 \u0442\u0435\u0445, \u043A\u0442\u043E \u0445\u043E\u0442\u0435\u043B \u0431\u044B \u043F\u043E \u043D\u0438\u043C \u043F\u0440\u043E\u0439\u0442\u0438\u0441\u044C.</p><p>\u041F\u0435\u0448\u0430\u044F \u043B\u0438\u0433\u0430 \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u043A\u043B\u0443\u0431\u044B \u043B\u044E\u0434\u0435\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043B\u044E\u0431\u044F\u0442 \u0437\u0430\u043F\u0438\u0441\u044B\u0432\u0430\u0442\u044C, \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0442\u044C \u0438 \u043E\u0431\u0441\u0443\u0436\u0434\u0430\u0442\u044C \u0441 \u0434\u0440\u0443\u0437\u044C\u044F\u043C\u0438 \u0441\u0432\u043E\u0438 \u043B\u044E\u0431\u0438\u043C\u044B\u0435 \u043C\u0435\u0441\u0442\u0430 \u0434\u043B\u044F \u043F\u0440\u043E\u0433\u0443\u043B\u043E\u043A. \u041A\u0442\u043E-\u0442\u043E \u0431\u0443\u0434\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0447\u0430\u0442\u044C \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u044B \u043D\u0430\u043A\u043B\u0435\u0439\u043A\u0430\u043C\u0438, \u0442\u0430\u0431\u043B\u0438\u0447\u043A\u0430\u043C\u0438, \u0437\u043D\u0430\u043A\u0430\u043C\u0438. \u041A\u0442\u043E-\u0442\u043E \u2013 \u0441\u043E\u0431\u0438\u0440\u0430\u0442\u044C \u043D\u0430 \u043F\u0440\u043E\u0433\u0443\u043B\u043A\u0438 \u0441\u0430\u043C\u044B\u0445 \u0440\u0430\u0437\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439. \u041A\u043E\u043C\u0443-\u0442\u043E \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u0435\u0435 \u0433\u0443\u043B\u044F\u0442\u044C \u0432 \u043E\u0434\u0438\u043D\u043E\u0447\u043A\u0443, \u043C\u0435\u043D\u044F\u044F \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u044B \u043D\u0430 \u0445\u043E\u0434\u0443.</p><p>\u041F\u0435\u0448\u0430\u044F \u043B\u0438\u0433\u0430 \u2013 \u0435\u0434\u0438\u043D\u0438\u0446\u0430 \u0434\u043B\u0438\u043D\u044B, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u043D\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0439 \u0445\u043E\u0434\u044C\u0431\u0435. \u042D\u0442\u043E \u0440\u0430\u0441\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u043E\u0439\u0442\u0438 \u0437\u0430 1 \u0447\u0430\u0441. \u0414\u043B\u044F \u043E\u0431\u0449\u0435\u0439 \u043C\u0435\u0440\u044B 1 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u043D\u0430\u044F \u043F\u0435\u0448\u0430\u044F \u043B\u0438\u0433\u0430 = 5 \u043A\u0438\u043B\u043E\u043C\u0435\u0442\u0440\u043E\u0432, \u0445\u043E\u0442\u044F \u0432 \u0442\u043E\u0447\u043D\u043E\u0441\u0442\u0438 \u044D\u0442\u0430 \u0446\u0438\u0444\u0440\u0430 \u0443 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u0432\u043E\u044F.</p><p>\u041E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u0443\u044F\u0441\u044C \u043D\u0430 \u044D\u0442\u0443 \u043C\u0435\u0440\u0443 \u0432\u0441\u0435 \u043C\u0430\u0448\u0440\u0443\u0442\u044B \u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0438\u0442\u044C \u043D\u0430 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u0438-\u0440\u0430\u0441\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043E\u043D\u0438 \u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0442. \u041A\u043E\u0440\u043E\u0442\u043A\u0438\u0435 \u043F\u0440\u043E\u0433\u0443\u043B\u043A\u0438 \u043C\u043E\u0433\u0443\u0442\u044C \u0431\u044B\u0442\u044C \u043D\u0430 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0443 \u043F\u0435\u0448\u0435\u0439 \u043B\u0438\u0433\u0438 \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u043D\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u044C. \u0414\u043E\u043B\u0433\u0438\u0435 \u2013 \u043E\u0442 2 \u0434\u043E 5 \u0447\u0430\u0441\u043E\u0432 \u0445\u043E\u0434\u044C\u0431\u044B. \u041D\u0430 \u0446\u0435\u043B\u044B\u0439 \u0434\u0435\u043D\u044C \u2013 \u043E\u0442 5 \u0434\u043E 10 \u043B\u0438\u0433 \u0438\u043B\u0438 \u043E\u0442 25 \u0434\u043E 50 \u043A\u043C. \u041F\u043E\u0445\u043E\u0434\u044B \u2013 \u043E\u0442 10 \u0438 \u0431\u0435\u0437 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439.</p><p>\u042D\u043D\u0442\u0443\u0437\u0438\u0430\u0441\u0442\u044B \u0437\u0430\u043C\u0435\u0440\u044F\u044E\u0442 \u0432\u0440\u0435\u043C\u044F \u0445\u043E\u0434\u044C\u0431\u044B \u043C\u0435\u0436\u0434\u0443 \u043A\u043B\u044E\u0447\u0435\u0432\u044B\u043C\u0438 \u0442\u043E\u0447\u043A\u0430\u043C\u0438 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0430 \u0438 \u0440\u0430\u0437\u043C\u0435\u0447\u0430\u044E\u0442 \u0435\u0433\u043E \u043C\u0435\u0442\u043A\u0430\u043C\u0438 \u043A\u0430\u043A \u043D\u0430 \u043A\u0430\u0440\u0442\u0435, \u0442\u0430\u043A \u0438 \u043D\u0430 \u043C\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u0438 \u2013 \u0437\u043D\u0430\u043A\u0430\u043C\u0438, \u043D\u0430\u043A\u043B\u0435\u0439\u043A\u0430\u043C\u0438 \u0438\u043B\u0438 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044F\u043C\u0438 \u0438 \u0432\u043D\u043E\u0441\u044F\u0442 \u0435\u0433\u043E \u0432 \u043E\u0431\u0449\u0438\u0439 \u043A\u0430\u0442\u0430\u043B\u043E\u0433 \u043F\u0440\u043E\u0433\u0443\u043B\u043E\u043A. \u041F\u0440\u043E\u0441\u0442\u043E \u0442\u0430\u043A \u0438\u043C \u0432\u0435\u0441\u0435\u043B\u0435\u0435 \u0436\u0438\u0442\u044C. \u0410 \u0442\u0430\u043A \u043C\u044B \u0432\u0441\u0435 \u0441\u043C\u043E\u0436\u0435\u043C \u0443\u0432\u0438\u0434\u0435\u0442\u044C \u0441\u0435\u0442\u044C \u043F\u0435\u0440\u0435\u0441\u0435\u043A\u0430\u044E\u0449\u0438\u0445\u0441\u044F \u043B\u0438\u043D\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043C\u044B \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u043C \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u043F\u043E \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438 \u043D\u0430\u0448\u0435\u0439 \u043F\u043B\u0430\u043D\u0435\u0442\u044B.</p><p>\u041C\u0435\u0441\u0442\u043D\u044B\u0435 \u043F\u0435\u0448\u0438\u0435 \u043A\u043B\u0443\u0431\u044B \u0432\u0441\u0442\u0430\u043D\u0443\u0442 \u043D\u0430 \u0437\u0430\u0449\u0438\u0442\u0443 \u043F\u0440\u0430\u0432\u0430 \u0436\u0438\u0442\u0435\u043B\u0435\u0439 \u043D\u0430 \u0437\u0434\u043E\u0440\u043E\u0432\u0443\u044E \u043F\u0440\u043E\u0433\u0443\u043B\u043A\u0443 \u0438 \u043F\u043E\u043C\u043E\u0433\u0443\u0442 \u0437\u0430\u043D\u043E\u0432\u043E \u0443\u0432\u0438\u0434\u0435\u0442\u044C \u043F\u043B\u043E\u0449\u0430\u0434\u0438, \u043F\u0435\u0448\u0438\u0435 \u0443\u043B\u0438\u0446\u044B, \u043D\u0430\u0431\u0435\u0440\u0435\u0436\u043D\u044B\u0435, \u043F\u0430\u0440\u043A\u0438, \u043F\u043E\u043B\u044F \u0438 \u043B\u0435\u0441\u0430 \u043A\u0430\u043A \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0438 \u0432\u0430\u0436\u043D\u043E\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E. \u0410 \u041F\u0435\u0448\u0430\u044F \u043B\u0438\u0433\u0430 \u043F\u043E\u043C\u043E\u0436\u0435\u0442 \u0441\u0432\u044F\u0437\u0430\u0442\u044C \u044D\u0442\u0438 \u043A\u043B\u0443\u0431\u044B \u0432 \u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u0443\u044E \u0441\u0435\u0442\u044C \u043F\u0443\u0442\u0435\u0439 \u0438 \u043F\u0443\u0442\u0435\u0432\u043E\u0434\u0438\u0442\u0435\u043B\u0435\u0439.</p>',10),s=[r];function d(l,h,c,o,_,p){return t(),a("div",null,s)}var g=e(i,[["render",d]]);export{f as __pageData,g as default};
